function kepler(M,e){M=rev(M);let E=M+R2D*e*S(M)*(1+e*C(M));for(let k=0;k<6;k++)E=E-(E-R2D*e*S(E)-M)/(1-e*C(E));return E;}

function helio(el){const E=kepler(el.M,el.e);const xv=el.a*(C(E)-el.e),yv=el.a*Math.sqrt(1-el.e*el.e)*S(E);const r=Math.hypot(xv,yv),v=atan2d(yv,xv);
  const xh=r*(C(el.N)*C(v+el.w)-S(el.N)*S(v+el.w)*C(el.i));const yh=r*(S(el.N)*C(v+el.w)+C(el.N)*S(v+el.w)*C(el.i));const zh=r*(S(v+el.w)*S(el.i));
  return {r,v,xh,yh,zh};}

function sunLon(d){const s=ELEM.Sun(d);const su=helio(s);return {lon:rev(su.v+s.w),xs:su.r*C(rev(su.v+s.w)),ys:su.r*S(rev(su.v+s.w))};}

