    const parts=line.split(/[,\t]/).map(s=>s.trim()).filter(x=>x!=="");
    if(!parts.length)return;
    const tok=parts[0]; let label=parts.slice(1).join(" ").trim();
    let m=tok.match(/^(\d{4})[-/](\d{1,2})[-/](\d{1,2})(?:[ T](\d{1,2}):(\d{2}))?$/);
    if(m){const dt=new Date(Date.UTC(+m[1],+m[2]-1,+m[3],+(m[4]||0),+(m[5]||0)));out.push({t:decYear(dt),date:dt,label});return;}
